var e=[{id:`L3_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_ROOT`,text:{KOREA:`으으, 코스가 왜 이렇게 험한 거야?! 처음 설계랑 완전히 달라졌잖아!`,JPN:`うう、なんて険しいコース！？　最初の設計と全然違うよ！`,ENG:`Eergh... What's with this ride?! It wasn't like this at all when it was first designed!`,TWN:`唔，路線怎麼這麼崎嶇？！根本和原本的設計完全不一樣！`},stage:{bg:`CLOSE`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_DESPAIR`}}}},{id:`L4_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`CLOSE`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_DESPAIR`}}}},{id:`L5_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_ROOT`,text:{KOREA:`시, 시그마? 괜찮아? 무섭지 않아?`,JPN:`し、シグマ？　大丈夫？　怖くない？`,ENG:`S-Sigma? You okay? You're not scared?`,TWN:`西…西格瑪？還好嗎？你不怕嗎？`},stage:{bg:`CLOSE`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_DESPAIR`}}}},{id:`L6_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`응. 난 괜찮아. 그치만 친구들이 힘들어해서 속상해.`,JPN:`うん、私は大丈夫。でも友達が辛そうで悲しい。`,ENG:`No. I'm fine. But I'm sad that my friends are having a bad time.`,TWN:`嗯，我沒事，只是有點難過看到朋友們這麼痛苦。`},stage:{bg:`CLOSE`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_DESPAIR`}}}},{id:`L7_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`타는 사람들을 괴롭히려는 것만 같아! 뿌우- 이런 건 놀이기구가 아니야!`,JPN:`乗ってる人をいじめてるだけみたいなんだもん！　むぅ～こんなのはアトラクションじゃないよ！`,ENG:`It's as if it was designed to terrorize the riders. Boo! This isn't a roller coaster at all!`,TWN:`這根本只是想折磨搭的人而已！哼！這不能算是遊樂器材！`},stage:{bg:`CLOSE`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_DESPAIR`}}}},{id:`L8_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_ROOT`,text:{KOREA:`……마, 맞아! 이런 건 놀이기구가 아니야! 뿌우-`,JPN:`……そ、そうだよ！　こんなのアトラクションじゃない！　むぅ～`,ENG:`…R-right! This isn't a roller coaster at all! Boo!!`,TWN:`……沒…沒錯！這才不能算是遊樂器材！哼哼！`},stage:{bg:`CLOSE`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_SERIOUS`}}}},{id:`L9_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_ROOT`,text:{KOREA:`그러니까 좀 세워 주면 안 될까!?`,JPN:`だから止めてくれないかな！？`,ENG:`So can you please let me off this thing?!`,TWN:`那可以讓它停下來嗎！？`},stage:{bg:`CLOSE`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_DESPAIR`}}}},{id:`L11_1`,type:`dialog`,speaker:`MC_HAVEN_NULL_NULL`,text:{KOREA:`중도 포기하시는 건가요?`,JPN:`途中放棄ですか？`,ENG:`Are you giving up?`,TWN:`你們打算中途放棄嗎？`},stage:{bg:`CLOSE`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MC_HAVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_ROOT`,text:{KOREA:`아, 안 되지… 그럼 하다 못해 속도라도 좀 낮춰 줘!`,JPN:`だ、ダメだよね……じゃあせめてスピードだけでも落としてくれ！`,ENG:`N-no, I can't give up... But can you at least slow it down a little?!`,TWN:`當…當然不是…那最起碼可以減個速吧！`},stage:{bg:`CLOSE`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_DESPAIR`},R:null}}}];export{e as default};